Here's a well-structured Discord.js v14 bot implementation with a single slash command, `/ban`, focusing on clarity and best practices:

```javascript
const { Client, SlashCommandBuilder, EmbedBuilder, Permissions } = require('discord.js');

const client = new Client({ intents: ['GUILDS', 'GUILD_MEMBERS'] });

// Command Definition
const banCommand = new SlashCommandBuilder()
   .setName('ban')
   .setDescription('Bans a user from the server.')
   .addUserOption(option =>
        option.setName('target')
           .setDescription('The user to ban')
           .setRequired(true)
    )
   .addStringOption(option =>
        option.setName('reason')
           .setDescription('Reason for the ban (optional)')
           .setRequired(false)
    )
   .setDefaultMemberPermissions(Permissions.FLAGS.BAN_MEMBERS); // Required permission

client.on('ready', () => {
    console.log(`Logged in as ${client.user.tag}!`);

    const guildId = process.env.TARGET_GUILD? parseInt(process.env.TARGET_GUILD) : null; // Optional guild-specific registration

    // Register command globally OR in a specific guild (see env variable logic)
    client.application.commands.set([banCommand.toJSON()])
       .then(() => {
            console.log('Slash command /ban registered.');
            if (guildId) {
                const guild = client.guilds.cache.get(guildId);
                if (guild) {
                    guild.commands.set([banCommand.toJSON()])
                       .then(() => console.log(`Command set in guild ${guildId}`))
                       .catch(error => console.error('Guild-specific command error:', error));
                } else {
                    console.warn('Guild ID provided but not found.');
                }
            }
        })
       .catch(error => console.error('Command registration error:', error));
});

client.on('interactionCreate', async interaction => {
    if (!interaction.isChatInputCommand()) return;

    const { commandName } = interaction;

    switch (commandName) {
        case 'ban':
            await handleBanCommand(interaction);
            break;
        default:
            console.error(`Unhandled command: ${commandName}`);
            interaction.reply({ content: 'Unknown command.', ephemeral: true });
    }
});

async function handleBanCommand(interaction) {
    try {
        const targetUser = interaction.options.getUser('target');
        const reason = interaction.options.getString('reason') || 'No reason provided';

        if (!interaction.guild.members.bannable(targetUser)) {
            return interaction.reply({
                content: 'Cannot ban this user. Missing permissions or higher role.',
                ephemeral: true
            });
        }

        await interaction.guild.members.ban(targetUser, { reason });

        const embed = new EmbedBuilder()
           .setTitle('User Banned')
           .setDescription(`Banned ${targetUser.tag} for: ${reason}`)
           .setColor(0x00AE86); // Green for success

        await interaction.reply({ embeds: [embed], ephemeral: true });
    } catch (error) {
        console.error(`Error banning user ${targetUser.id}:`, error);
        interaction.reply({ content: 'An error occurred while banning the user.', ephemeral: true });
    }
}

client.login(process.env.BOT_TOKEN);
```

